targets.expr:
(
  100 * sum by(groupId) (
    (
      kube_pod_container_resource_requests{resource="hygon_com_dcu"} != 0
      and on(pod, namespace) kube_pod_status_phase{phase="Running"}
      unless on(pod, namespace) kube_pod_deletion_timestamp > 0
    )
    * on(node) group_left(groupId)
      max by(node, groupId) (resource_group_node_capacity_cards{groupId=~"$groupId",groupId!=""} >= bool 0)
  ) / sum by(groupId) (
    kube_node_status_capacity{resource="hygon_com_dcu"}
    * on(node) group_left(groupId)
      max by(node, groupId) (resource_group_node_capacity_cards{groupId=~"$groupId",groupId!=""} >= bool 0)
  )
)
and on(groupId)
(
  sum by(groupId) (
